# OEIS sequence: A393710

import math
def A393710(n):
    if n == 0: return 0
    count = 0
    bound_x = math.isqrt(n-1)
    for x in range(1, bound_x+1):
        yz = n - x**2
        bound_y = math.isqrt(yz-1)
        for y in range(x+1, bound_y+1):
            if yz % y == 0:
                z = yz // y
                if z > y:
                    count += 1
    return count
